"use strict";(()=>{const t=()=>{if(window.matchMedia("(pointer: coarse)").matches||window.matchMedia("(prefers-reduced-motion: reduce)").matches||document.querySelectorAll(".glass-glow").length===0)return;const o=document.documentElement;let n=-9999,r=-9999,e=!1;document.addEventListener("mousemove",s=>{n=s.clientX,r=s.clientY,e||(e=!0,requestAnimationFrame(()=>{e=!1,o.style.setProperty("--glow-x",`${n}px`),o.style.setProperty("--glow-y",`${r}px`)}))})};document.readyState==="loading"?document.addEventListener("DOMContentLoaded",t):t()})();
